  1→//! Kimi Code provider.
  2→//!
  3→//! Authentication uses the Kimi device-flow OAuth (same as kimi-cli).
  4→//! The API is OpenAI-compatible at `https://api.kimi.com/coding/v1`.
  5→
  6→use std::pin::Pin;
  7→
  8→use {
  9→    async_trait::async_trait,
 10→    futures::StreamExt,
 11→    moltis_oauth::{OAuthTokens, TokenStore, kimi_headers},
 12→    secrecy::{ExposeSecret, Secret},
 13→    tokio_stream::Stream,
 14→    tracing::{debug, trace, warn},
 15→};
 16→
 17→use {
 18→    super::openai_compat::{
 19→        SseLineResult, StreamingToolState, finalize_stream, parse_openai_compat_usage_from_payload,
 20→        parse_tool_calls, process_openai_sse_line, to_openai_tools,
 21→    },
 22→    moltis_agents::model::{ChatMessage, CompletionResponse, LlmProvider, StreamEvent},
 23→};
 24→
 25→// ── Constants ────────────────────────────────────────────────────────────────
 26→
 27→const KIMI_API_BASE: &str = "https://api.kimi.com/coding/v1";
 28→const KIMI_AUTH_HOST: &str = "https://auth.kimi.com";
 29→const KIMI_CLIENT_ID: &str = "17e5f671-d194-4dfb-9706-5516cb48c098";
 30→const PROVIDER_NAME: &str = "kimi-code";
 31→
 32→/// Refresh threshold: 5 minutes before expiry.
 33→const REFRESH_THRESHOLD_SECS: u64 = 300;
 34→
 35→// ── Provider ─────────────────────────────────────────────────────────────────
 36→
 37→enum AuthMode {
 38→    OAuthTokenStore { token_store: TokenStore },
 39→    ApiKey { api_key: Secret<String> },
 40→}
 41→
 42→pub struct KimiCodeProvider {
 43→    model: String,
 44→    client: &'static reqwest::Client,
 45→    base_url: String,
 46→    auth_mode: AuthMode,
 47→}
 48→
 49→impl KimiCodeProvider {
 50→    /// Build a provider that authenticates via Kimi OAuth tokens.
 51→    pub fn new(model: String) -> Self {
 52→        Self {
 53→            model,
 54→            client: crate::shared_http_client(),
 55→            base_url: KIMI_API_BASE.into(),
 56→            auth_mode: AuthMode::OAuthTokenStore {
 57→                token_store: TokenStore::new(),
 58→            },
 59→        }
 60→    }
 61→
 62→    /// Build a provider that authenticates via API key.
 63→    pub fn new_with_api_key(api_key: Secret<String>, model: String, base_url: String) -> Self {
 64→        Self {
 65→            model,
 66→            client: crate::shared_http_client(),
 67→            base_url,
 68→            auth_mode: AuthMode::ApiKey { api_key },
 69→        }
 70→    }
 71→
 72→    fn should_send_kimi_headers(&self) -> bool {
 73→        matches!(self.auth_mode, AuthMode::OAuthTokenStore { .. })
 74→    }
 75→
 76→    async fn get_auth_token(&self) -> anyhow::Result<String> {
 77→        match &self.auth_mode {
 78→            AuthMode::ApiKey { api_key } => Ok(api_key.expose_secret().clone()),
 79→            AuthMode::OAuthTokenStore { .. } => self.get_valid_oauth_token().await,
 80→        }
 81→    }
 82→
 83→    /// Load tokens and refresh if needed (< 5 min remaining).
 84→    async fn get_valid_oauth_token(&self) -> anyhow::Result<String> {
 85→        let AuthMode::OAuthTokenStore { token_store } = &self.auth_mode else {
 86→            return Err(anyhow::anyhow!("oauth token store is not configured"));
 87→        };
 88→        let tokens = token_store.load(PROVIDER_NAME).ok_or_else(|| {
 89→            anyhow::anyhow!(
 90→                "not logged in to kimi-code — run `moltis auth login --provider kimi-code`"
 91→            )
 92→        })?;
 93→
 94→        // Check expiry with 5 min buffer
 95→        if let Some(expires_at) = tokens.expires_at {
 96→            let now = std::time::SystemTime::now()
 97→                .duration_since(std::time::UNIX_EPOCH)
 98→                .unwrap_or_default()
 99→                .as_secs();
100→            if now + REFRESH_THRESHOLD_SECS >= expires_at {
101→                if let Some(ref refresh_token) = tokens.refresh_token {
102→                    debug!("refreshing kimi-code token");
103→                    let new_tokens =
104→                        refresh_access_token(self.client, refresh_token.expose_secret()).await?;
105→                    token_store.save(PROVIDER_NAME, &new_tokens)?;
106→                    return Ok(new_tokens.access_token.expose_secret().clone());
107→                }
108→                return Err(anyhow::anyhow!(
109→                    "kimi-code token expired and no refresh token available"
110→                ));
111→            }
112→        }
113→
114→        Ok(tokens.access_token.expose_secret().clone())
115→    }
116→}
117→
118→fn build_access_denied_hint(status: reqwest::StatusCode, body_text: &str) -> Option<String> {
119→    if status == reqwest::StatusCode::FORBIDDEN && body_text.contains("access_terminated_error") {
120→        return Some(
121→            "Kimi OAuth access is restricted for this account/client. Configure `kimi-code` with `KIMI_API_KEY` (or [providers.kimi-code].api_key) and use API-key auth.".into(),
122→        );
123→    }
124→    None
125→}
126→
127→/// Refresh the access token using the Kimi token endpoint.
128→pub async fn refresh_access_token(
129→    client: &reqwest::Client,
130→    refresh_token: &str,
131→) -> anyhow::Result<OAuthTokens> {
132→    let headers = kimi_headers();
133→    let resp = client
134→        .post(format!("{KIMI_AUTH_HOST}/api/oauth/token"))
135→        .headers(headers)
136→        .header("Accept", "application/json")
137→        .form(&[
138→            ("client_id", KIMI_CLIENT_ID),
139→            ("grant_type", "refresh_token"),
140→            ("refresh_token", refresh_token),
141→        ])
142→        .send()
143→        .await?;
144→
145→    if !resp.status().is_success() {
146→        let body = resp.text().await.unwrap_or_default();
147→        anyhow::bail!("kimi-code token refresh failed: {body}");
148→    }
149→
150→    #[derive(serde::Deserialize)]
151→    struct RefreshResponse {
152→        access_token: String,
153→        refresh_token: Option<String>,
154→        expires_in: Option<u64>,
155→    }
156→
157→    let body: RefreshResponse = resp.json().await?;
158→    let expires_at = body.expires_in.map(|secs| {
159→        std::time::SystemTime::now()
160→            .duration_since(std::time::UNIX_EPOCH)
161→            .unwrap_or_default()
162→            .as_secs()
163→            + secs
164→    });
165→
166→    Ok(OAuthTokens {
167→        access_token: Secret::new(body.access_token),
168→        refresh_token: body.refresh_token.map(Secret::new),
169→        id_token: None,
170→        account_id: None,
171→        expires_at,
172→    })
173→}
174→
175→/// Check if we have stored tokens for Kimi Code.
176→pub fn has_stored_tokens() -> bool {
177→    TokenStore::new().load(PROVIDER_NAME).is_some()
178→}
179→
180→/// Known Kimi Code models.
181→pub const KIMI_CODE_MODELS: &[(&str, &str)] = &[
182→    ("kimi-for-coding", "Kimi For Coding"),
183→    ("kimi-k2.5", "Kimi K2.5"),
184→];
