186→// ── LlmProvider impl ────────────────────────────────────────────────────────
187→
188→#[async_trait]
189→impl LlmProvider for KimiCodeProvider {
190→    fn name(&self) -> &str {
191→        PROVIDER_NAME
192→    }
193→
194→    fn id(&self) -> &str {
195→        &self.model
196→    }
197→
198→    fn supports_tools(&self) -> bool {
199→        true
200→    }
201→
202→    async fn complete(
203→        &self,
204→        messages: &[ChatMessage],
205→        tools: &[serde_json::Value],
206→    ) -> anyhow::Result<CompletionResponse> {
207→        let token = self.get_auth_token().await?;
208→
209→        let openai_messages: Vec<serde_json::Value> =
210→            messages.iter().map(ChatMessage::to_openai_value).collect();
211→        let mut body = serde_json::json!({
212→            "model": self.model,
213→            "messages": openai_messages,
214→        });
215→
216→        if !tools.is_empty() {
217→            body["tools"] = serde_json::Value::Array(to_openai_tools(tools, true));
218→        }
219→
220→        debug!(
221→            model = %self.model,
222→            messages_count = messages.len(),
223→            tools_count = tools.len(),
224→            "kimi-code complete request"
225→        );
226→        trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "kimi-code request body");
227→
228→        let mut request = self
229→            .client
230→            .post(format!("{}/chat/completions", self.base_url))
231→            .header("Authorization", format!("Bearer {token}"))
232→            .header("content-type", "application/json");
233→        if self.should_send_kimi_headers() {
234→            request = request.headers(kimi_headers());
235→        }
236→        let http_resp = request.json(&body).send().await?;
237→
238→        let status = http_resp.status();
239→        if !status.is_success() {
240→            let retry_after_ms = super::retry_after_ms_from_headers(http_resp.headers());
241→            let body_text = http_resp.text().await.unwrap_or_default();
242→            warn!(status = %status, body = %body_text, "kimi-code API error");
243→            let hint = build_access_denied_hint(status, &body_text);
244→            if let Some(hint) = hint {
245→                anyhow::bail!(
246→                    "{}",
247→                    super::with_retry_after_marker(
248→                        format!("Kimi Code API error HTTP {status}: {body_text} ({hint})"),
249→                        retry_after_ms,
250→                    )
251→                );
252→            }
253→            anyhow::bail!(
254→                "{}",
255→                super::with_retry_after_marker(
256→                    format!("Kimi Code API error HTTP {status}: {body_text}"),
257→                    retry_after_ms,
258→                )
259→            );
260→        }
261→
262→        let resp = http_resp.json::<serde_json::Value>().await?;
263→        trace!(response = %resp, "kimi-code raw response");
264→
265→        let message = &resp["choices"][0]["message"];
266→
267→        let text = message["content"].as_str().map(|s| s.to_string());
268→        let tool_calls = parse_tool_calls(message);
269→
270→        let usage = parse_openai_compat_usage_from_payload(&resp).unwrap_or_default();
271→
272→        Ok(CompletionResponse {
273→            text,
274→            tool_calls,
275→            usage,
276→        })
277→    }
278→
279→    #[allow(clippy::collapsible_if)]
280→    fn stream(
281→        &self,
282→        messages: Vec<ChatMessage>,
283→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
284→        self.stream_with_tools(messages, vec![])
285→    }
286→
287→    #[allow(clippy::collapsible_if)]
288→    fn stream_with_tools(
289→        &self,
290→        messages: Vec<ChatMessage>,
291→        tools: Vec<serde_json::Value>,
292→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
293→        Box::pin(async_stream::stream! {
294→            let token = match self.get_auth_token().await {
295→                Ok(t) => t,
296→                Err(e) => {
297→                    yield StreamEvent::Error(e.to_string());
298→                    return;
299→                }
300→            };
301→
302→            let openai_messages: Vec<serde_json::Value> =
303→                messages.iter().map(ChatMessage::to_openai_value).collect();
304→            let mut body = serde_json::json!({
305→                "model": self.model,
306→                "messages": openai_messages,
307→                "stream": true,
308→                "stream_options": { "include_usage": true },
309→            });
310→
311→            if !tools.is_empty() {
312→                body["tools"] = serde_json::Value::Array(to_openai_tools(&tools, true));
313→            }
314→
315→            debug!(
316→                model = %self.model,
317→                messages_count = openai_messages.len(),
318→                tools_count = tools.len(),
319→                "kimi-code stream_with_tools request"
320→            );
321→            trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "kimi-code stream request body");
322→
323→            let mut request = self
324→                .client
325→                .post(format!("{}/chat/completions", self.base_url))
326→                .header("Authorization", format!("Bearer {token}"))
327→                .header("content-type", "application/json");
328→            if self.should_send_kimi_headers() {
329→                request = request.headers(kimi_headers());
330→            }
331→
332→            let resp = match request.json(&body).send().await {
333→                Ok(r) => {
334→                    if let Err(e) = r.error_for_status_ref() {
335→                        let status = e.status().map(|s| s.as_u16()).unwrap_or(0);
336→                        let retry_after_ms = super::retry_after_ms_from_headers(r.headers());
337→                        let body_text = r.text().await.unwrap_or_default();
338→                        let hint = build_access_denied_hint(
339→                            reqwest::StatusCode::from_u16(status)
340→                                .unwrap_or(reqwest::StatusCode::INTERNAL_SERVER_ERROR),
341→                            &body_text,
342→                        );
343→                        if let Some(hint) = hint {
344→                            yield StreamEvent::Error(super::with_retry_after_marker(
345→                                format!("HTTP {status}: {body_text} ({hint})"),
346→                                retry_after_ms,
347→                            ));
348→                        } else {
349→                            yield StreamEvent::Error(super::with_retry_after_marker(
350→                                format!("HTTP {status}: {body_text}"),
351→                                retry_after_ms,
352→                            ));
353→                        }
354→                        return;
355→                    }
356→                    r
357→                }
358→                Err(e) => {
359→                    yield StreamEvent::Error(e.to_string());
360→                    return;
361→                }
362→            };
363→
364→            let mut byte_stream = resp.bytes_stream();
365→            let mut buf = String::new();
366→            let mut state = StreamingToolState::default();
367→
368→            while let Some(chunk) = byte_stream.next().await {
369→                let chunk = match chunk {
370→                    Ok(c) => c,
371→                    Err(e) => {
372→                        yield StreamEvent::Error(e.to_string());
373→                        return;
374→                    }
375→                };
376→                buf.push_str(&String::from_utf8_lossy(&chunk));
377→
378→                while let Some(pos) = buf.find('\n') {
379→                    let line = buf[..pos].trim().to_string();
380→                    buf = buf[pos + 1..].to_string();
381→
382→                    if line.is_empty() {
383→                        continue;
384→                    }
385→
386→                    let Some(data) = line
387→                        .strip_prefix("data: ")
388→                        .or_else(|| line.strip_prefix("data:"))
389→                    else {
390→                        continue;
391→                    };
392→
393→                    match process_openai_sse_line(data, &mut state) {
394→                        SseLineResult::Done => {
395→                            for event in finalize_stream(&mut state) {
396→                                yield event;
397→                            }
398→                            return;
399→                        }
400→                        SseLineResult::Events(events) => {
401→                            for event in events {
402→                                yield event;
403→                            }
404→                        }
405→                        SseLineResult::Skip => {}
406→                    }
407→                }
408→            }
409→
410→            let line = buf.trim().to_string();
411→            if !line.is_empty()
412→                && let Some(data) = line
413→                    .strip_prefix("data: ")
414→                    .or_else(|| line.strip_prefix("data:"))
415→            {
416→                match process_openai_sse_line(data, &mut state) {
417→                    SseLineResult::Done => {
418→                        for event in finalize_stream(&mut state) {
419→                            yield event;
420→                        }
421→                        return;
422→                    }
423→                    SseLineResult::Events(events) => {
424→                        for event in events {
425→                            yield event;
426→                        }
427→                    }
428→                    SseLineResult::Skip => {}
429→                }
430→            }
431→
432→            for event in finalize_stream(&mut state) {
433→                yield event;
434→            }
435→        })
436→    }
437→}
