454→    async fn start_mock_with_capture(
455→        response_body: serde_json::Value,
456→    ) -> (String, Arc<Mutex<Vec<CapturedRequest>>>) {
457→        let captured: Arc<Mutex<Vec<CapturedRequest>>> = Arc::new(Mutex::new(Vec::new()));
458→        let captured_clone = captured.clone();
459→        let resp_body = response_body.clone();
460→
461→        let app = Router::new().route(
462→            "/chat/completions",
463→            post(move |req: Request| {
464→                let cap = captured_clone.clone();
465→                let resp = resp_body.clone();
466→                async move {
467→                    let headers: Vec<(String, String)> = req
468→                        .headers()
469→                        .iter()
470→                        .map(|(k, v)| {
471→                            (k.as_str().to_string(), v.to_str().unwrap_or("").to_string())
472→                        })
473→                        .collect();
474→
475→                    let body_bytes = axum::body::to_bytes(req.into_body(), 1024 * 1024)
476→                        .await
477→                        .unwrap_or_default();
478→                    let body: Option<serde_json::Value> = serde_json::from_slice(&body_bytes).ok();
479→
480→                    cap.lock().unwrap().push(CapturedRequest { headers, body });
481→
482→                    axum::Json(resp)
483→                }
484→            }),
485→        );
486→
487→        let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
488→        let addr = listener.local_addr().unwrap();
489→        tokio::spawn(async move {
490→            axum::serve(listener, app).await.unwrap();
491→        });
492→
493→        (format!("http://{addr}"), captured)
494→    }
