610→    #[tokio::test]
611→    async fn complete_sends_required_headers() {
612→        let (base_url, captured) = start_mock_with_capture(mock_completion_response()).await;
613→        let provider = mock_provider(&base_url, "kimi-k2.5");
614→
615→        let messages = vec![serde_json::json!({"role": "user", "content": "hi"})];
616→        let result = provider.complete(&messages, &[]).await;
617→        assert!(result.is_ok());
618→
619→        let reqs = captured.lock().unwrap();
620→        assert_eq!(reqs.len(), 1);
621→
622→        let req = &reqs[0];
623→
624→        // Verify X-Msh-* headers
625→        let has_platform = req.headers.iter().any(|(k, _)| k == "x-msh-platform");
626→        assert!(has_platform, "missing X-Msh-Platform header");
627→
628→        let has_device_id = req.headers.iter().any(|(k, _)| k == "x-msh-device-id");
629→        assert!(has_device_id, "missing X-Msh-Device-Id header");
