 36→    /// Register models from a [`RediscoveryResult`], skipping those already
 37→    /// present. All I/O (model list fetches, Ollama probes) must be completed
 38→    /// before calling this — it only does fast in-memory work.
 39→    ///
 40→    /// Returns the number of newly registered models.
 41→    pub fn register_rediscovered_models(
 42→        &mut self,
 43→        config: &ProvidersConfig,
 44→        env_overrides: &HashMap<String, String>,
 45→        result: &RediscoveryResult,
 46→    ) -> usize {
 47→        let fetched = &result.models;
 48→        let mut added = 0usize;
 49→
 50→        // ── Anthropic builtin ─────────────────────────────────────────
 51→        if fetched.contains_key("anthropic")
 52→            && config.is_enabled("anthropic")
 53→            && let Some(key) =
 54→                resolve_api_key(config, "anthropic", "ANTHROPIC_API_KEY", env_overrides)
 55→        {
 56→            let base_url = config
 57→                .get("anthropic")
 58→                .and_then(|e| e.base_url.clone())
 59→                .or_else(|| env_value(env_overrides, "ANTHROPIC_BASE_URL"))
 60→                .unwrap_or_else(|| "https://api.anthropic.com".into());
 61→            let alias = config.get("anthropic").and_then(|e| e.alias.clone());
 62→            let provider_label = alias.clone().unwrap_or_else(|| "anthropic".into());
 63→            let cache_retention = config
 64→                .get("anthropic")
 65→                .map(|e| e.cache_retention)
 66→                .unwrap_or(moltis_config::CacheRetention::Short);
 67→            let models = Self::desired_anthropic_models(config, fetched);
 68→            let provider_cw = config
 69→                .get("anthropic")
 70→                .map(|e| extract_cw_overrides(&e.model_overrides))
 71→                .unwrap_or_default();
 72→
 73→            added += self.replace_anthropic_catalog(
 74→                models,
 75→                &key,
 76→                &base_url,
 77→                &provider_label,
 78→                alias,
 79→                cache_retention,
 80→                provider_cw,
 81→            );
 82→        }
 83→
 84→        // ── OpenAI builtin ────────────────────────────────────────────
 85→        if let Some(models) = fetched.get("openai")
 86→            && config.is_enabled("openai")
 87→            && let Some(key) = resolve_api_key(config, "openai", "OPENAI_API_KEY", env_overrides)
 88→        {
 89→            let base_url = config
 90→                .get("openai")
 91→                .and_then(|e| e.base_url.clone())
 92→                .or_else(|| env_value(env_overrides, "OPENAI_BASE_URL"))
 93→                .unwrap_or_else(|| "https://api.openai.com/v1".into());
 94→            let alias = config.get("openai").and_then(|e| e.alias.clone());
 95→            let provider_label = alias.unwrap_or_else(|| "openai".into());
 96→            let stream_transport = config
 97→                .get("openai")
 98→                .map(|entry| entry.stream_transport)
 99→                .unwrap_or(ProviderStreamTransport::Sse);
100→
101→            for model in models {
102→                if self.has_provider_model(&provider_label, &model.id) {
103→                    continue;
104→                }
105→                let provider = Arc::new(
106→                    openai::OpenAiProvider::new_with_name(
107→                        key.clone(),
108→                        model.id.clone(),
109→                        base_url.clone(),
110→                        provider_label.clone(),
111→                    )
112→                    .with_stream_transport(stream_transport)
113→                    .with_context_window_overrides(
114→                        self.global_cw_overrides.clone(),
115→                        config
116→                            .get("openai")
117→                            .map(|e| extract_cw_overrides(&e.model_overrides))
118→                            .unwrap_or_default(),
119→                    ),
120→                );
121→                self.register(
122→                    ModelInfo {
123→                        id: model.id.clone(),
124→                        provider: provider_label.clone(),
125→                        display_name: model.display_name.clone(),
126→                        created_at: model.created_at,
127→                        recommended: model.recommended,
128→                        capabilities: model
129→                            .capabilities
130→                            .unwrap_or_else(|| ModelCapabilities::infer(&model.id)),
131→                    },
132→                    provider,
133→                );
134→                added += 1;
135→            }
136→        }
137→
138→        // ── OpenAI-compatible providers ───────────────────────────────
139→        for def in OPENAI_COMPAT_PROVIDERS {
140→            let Some(models) = fetched.get(def.config_name) else {
141→                continue;
142→            };
143→            if !config.is_enabled(def.config_name) {
144→                continue;
145→            }
146→
147→            let key = resolve_api_key(config, def.config_name, def.env_key, env_overrides);
148→            let key = if !def.requires_api_key {
149→                key.or_else(|| Some(secrecy::Secret::new(def.config_name.into())))
150→            } else if def.config_name == "gemini" {

150→            } else if def.config_name == "gemini" {
151→                key.or_else(|| env_value(env_overrides, "GOOGLE_API_KEY").map(secrecy::Secret::new))
152→            } else {
153→                key
154→            };
155→            let Some(key) = key else {
156→                continue;
157→            };
158→
159→            let base_url = config
160→                .get(def.config_name)
161→                .and_then(|e| e.base_url.clone())
162→                .or_else(|| env_value(env_overrides, def.env_base_url_key))
163→                .unwrap_or_else(|| def.default_base_url.into());
164→            let alias = config.get(def.config_name).and_then(|e| e.alias.clone());
165→            let provider_label = alias.unwrap_or_else(|| def.config_name.into());
166→            let stream_transport = config
167→                .get(def.config_name)
168→                .map(|entry| entry.stream_transport)
169→                .unwrap_or(ProviderStreamTransport::Sse);
170→            let cache_retention = config
171→                .get(def.config_name)
172→                .map(|e| e.cache_retention)
173→                .unwrap_or(moltis_config::CacheRetention::Short);
174→            let config_tool_mode = config
175→                .get(def.config_name)
176→                .map(|e| e.tool_mode)
177→                .unwrap_or_default();
178→            let is_ollama = def.config_name == "ollama";
179→
180→            // Use pre-fetched Ollama `/api/show` probes (already collected
181→            // outside the registry lock by `fetch_discoverable_models`).
182→            let empty_probes = HashMap::new();
183→            let ollama_probes: &HashMap<String, OllamaShowResponse> = if is_ollama {
184→                &result.ollama_probes
185→            } else {
186→                &empty_probes
187→            };
188→
189→            for model in models {
190→                if self.has_provider_model(&provider_label, &model.id) {
191→                    continue;
192→                }
193→                let effective_tool_mode = if is_ollama {
194→                    resolve_ollama_tool_mode(
195→                        config_tool_mode,
196→                        &model.id,
197→                        ollama_probes.get(&model.id),
198→                    )
199→                } else if !matches!(config_tool_mode, moltis_config::ToolMode::Auto) {
200→                    config_tool_mode
201→                } else {
202→                    moltis_config::ToolMode::Auto
203→                };
204→
205→                let mut oai = openai::OpenAiProvider::new_with_name(
206→                    key.clone(),
207→                    model.id.clone(),
208→                    base_url.clone(),
209→                    provider_label.clone(),
210→                )
211→                .with_stream_transport(stream_transport)
212→                .with_cache_retention(cache_retention)
213→                .with_context_window_overrides(
214→                    self.global_cw_overrides.clone(),
215→                    config
216→                        .get(def.config_name)
217→                        .map(|e| extract_cw_overrides(&e.model_overrides))
218→                        .unwrap_or_default(),
219→                );
220→
221→                if !matches!(effective_tool_mode, moltis_config::ToolMode::Auto) {
222→                    oai = oai.with_tool_mode(effective_tool_mode);
223→                }
224→                if let Some(strict) = config.get(def.config_name).and_then(|e| e.strict_tools) {
