  1→//! Live integration tests for the Moonshot (Kimi) provider.
  2→//!
  3→//! These tests hit the real Moonshot API and require `MOONSHOT_API_KEY` in the
  4→//! environment. They are `#[ignore]`d by default so `cargo test` skips them.
  5→//!
  6→//! Run with:
  7→//!   cargo test --test moonshot_integration -- --ignored
  8→
  9→#![allow(clippy::unwrap_used, clippy::expect_used)]
 10→
 11→use std::collections::HashSet;
 12→
 13→use {
 14→    futures::StreamExt,
 15→    moltis_agents::model::{ChatMessage, LlmProvider, StreamEvent, ToolCall},
 16→    moltis_providers::openai::OpenAiProvider,
 17→    secrecy::{ExposeSecret, Secret},
 18→};
 19→
 20→const MOONSHOT_BASE_URL: &str = "https://api.moonshot.ai/v1";
 21→const TEST_MODEL: &str = "kimi-k2.5";
 22→
 23→/// Known Moonshot models we catalog. Keep in sync with `MOONSHOT_MODELS` in
 24→/// `crates/providers/src/lib.rs`.
 25→const KNOWN_MODELS: &[&str] = &["kimi-k2.5"];
 26→
 27→fn api_key() -> Secret<String> {
 28→    let key = std::env::var("MOONSHOT_API_KEY")
 29→        .expect("MOONSHOT_API_KEY must be set for integration tests");
 30→    Secret::new(key)
 31→}
 32→
 33→fn make_provider(model: &str) -> OpenAiProvider {
 34→    OpenAiProvider::new_with_name(
 35→        api_key(),
 36→        model.to_string(),
 37→        MOONSHOT_BASE_URL.to_string(),
 38→        "moonshot".to_string(),
 39→    )
 40→}
