 42→/// Tool schema in moltis-internal flat format.
 43→fn weather_tool() -> serde_json::Value {
 44→    serde_json::json!({
 45→        "name": "get_weather",
 46→        "description": "Get current weather for a location. You MUST call this tool when asked about weather.",
 47→        "parameters": {
 48→            "type": "object",
 49→            "properties": {
 50→                "location": {
 51→                    "type": "string",
 52→                    "description": "City name"
 53→                }
 54→            },
 55→            "required": ["location"]
 56→        }
 57→    })
 58→}
 59→
 60→// ── System prompt handling ───────────────────────────────────────────────────
 61→
 62→/// System prompt must reach the model (Moonshot uses standard role: "system").
 63→#[tokio::test]
 64→#[ignore]
 65→async fn system_prompt_is_received_non_streaming() {
 66→    let p = make_provider(TEST_MODEL);
 67→    let keyword = "MANGO";
 68→    let messages = vec![
 69→        ChatMessage::system(format!(
 70→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
 71→        )),
 72→        ChatMessage::user("What is 2+2?"),
 73→    ];
 74→
 75→    let response = p
 76→        .complete(&messages, &[])
 77→        .await
 78→        .expect("non-streaming completion should succeed");
 79→
 80→    let text = response.text.expect("response must contain text");
 81→    assert!(
 82→        text.to_lowercase().contains(&keyword.to_lowercase()),
 83→        "system prompt was not received by model: response = {text:?}"
 84→    );
 85→    assert!(
 86→        response.usage.input_tokens > 0,
 87→        "should report input tokens"
 88→    );
 89→    assert!(
 90→        response.usage.output_tokens > 0,
 91→        "should report output tokens"
 92→    );
 93→}
 94→
 95→/// Streaming variant of the system prompt test.
 96→#[tokio::test]
 97→#[ignore]
 98→async fn system_prompt_is_received_streaming() {
 99→    let p = make_provider(TEST_MODEL);
100→    let keyword = "PAPAYA";
101→    let messages = vec![
102→        ChatMessage::system(format!(
103→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
104→        )),
105→        ChatMessage::user("What is 3+3?"),
106→    ];
107→
108→    let mut stream = p.stream_with_tools(messages, vec![]);
109→    let mut full_text = String::new();
110→    let mut saw_done = false;
111→
112→    while let Some(event) = stream.next().await {
113→        match event {
114→            StreamEvent::Delta(chunk) => full_text.push_str(&chunk),
115→            StreamEvent::Done(usage) => {
116→                saw_done = true;
117→                assert!(usage.input_tokens > 0, "should report input tokens");
118→                assert!(usage.output_tokens > 0, "should report output tokens");
119→                break;
120→            },
121→            StreamEvent::Error(err) => panic!("stream error: {err}"),
122→            _ => {},
123→        }
124→    }
125→
126→    assert!(saw_done, "stream must emit Done event");
127→    assert!(
128→        full_text.to_lowercase().contains(&keyword.to_lowercase()),
129→        "system prompt was not received by model: response = {full_text:?}"
130→    );
131→}
132→
133→// ── Tool calling ─────────────────────────────────────────────────────────────
134→
135→/// Model must be able to call a tool via non-streaming completion.
136→#[tokio::test]
137→#[ignore]
138→async fn tool_call_round_trip_non_streaming() {
139→    let p = make_provider(TEST_MODEL);
140→    let tools = vec![weather_tool()];
141→
142→    let messages = vec![ChatMessage::user(
143→        "What's the weather like in Tokyo? You must use the get_weather tool to answer.",
144→    )];
145→
146→    let response = p
147→        .complete(&messages, &tools)
148→        .await
149→        .expect("completion with tools should succeed");
150→
151→    assert!(
152→        !response.tool_calls.is_empty(),
153→        "model should call the get_weather tool, got text: {:?}",
154→        response.text
155→    );
156→
157→    let tool_call = &response.tool_calls[0];
158→    assert_eq!(tool_call.name, "get_weather");
159→    let args = &tool_call.arguments;
