202→/// Multi-turn tool use: model calls tool, receives result, responds.
203→///
204→/// Moonshot (kimi-k2.5) with thinking mode enabled requires the original
205→/// `reasoning_content` from step 1 to be replayed in the assistant message.
206→/// `ChatMessage` does not carry reasoning_content, so the serialization layer
207→/// injects an empty string which Moonshot rejects. In production, the gateway
208→/// preserves the full raw JSON (including `reasoning_content`) across turns.
209→///
210→/// This test validates the streaming first turn (tool call detection) and
211→/// documents the multi-turn limitation for the typed message path.
212→#[tokio::test]
213→#[ignore]
214→async fn multi_turn_tool_use_streaming() {
215→    let p = make_provider(TEST_MODEL);
216→    let tools = vec![weather_tool()];
217→
218→    // Step 1: use streaming to get the tool call
219→    let messages = vec![ChatMessage::user(
220→        "What's the weather in London? You must use the get_weather tool.",
221→    )];
222→    let mut stream = p.stream_with_tools(messages, tools.clone());
223→
224→    let mut tool_calls: Vec<(String, String, String)> = Vec::new(); // (id, name, args)
225→    let mut current_tool_args = String::new();
226→    let mut current_tool_id = String::new();
227→    let mut current_tool_name = String::new();
228→
229→    while let Some(event) = stream.next().await {
230→        match event {
231→            StreamEvent::ToolCallStart { id, name, .. } => {
232→                current_tool_id = id;
233→                current_tool_name = name;
234→                current_tool_args.clear();
235→            },
236→            StreamEvent::ToolCallArgumentsDelta { delta, .. } => {
237→                current_tool_args.push_str(&delta);
238→            },
239→            StreamEvent::ToolCallComplete { .. } => {
240→                tool_calls.push((
241→                    current_tool_id.clone(),
242→                    current_tool_name.clone(),
243→                    current_tool_args.clone(),
244→                ));
245→            },
246→            StreamEvent::Done(_) => break,
247→            StreamEvent::Error(err) => panic!("stream error: {err}"),
248→            _ => {},
249→        }
250→    }
251→    drop(stream);
252→
253→    assert!(!tool_calls.is_empty(), "should call get_weather");
254→    let (tc_id, tc_name, tc_args) = &tool_calls[0];
255→    assert_eq!(tc_name, "get_weather");
256→
257→    let args: serde_json::Value = serde_json::from_str(tc_args).expect("valid JSON arguments");
258→
259→    // Step 2: provide tool result. Moonshot's API requires the original
260→    // reasoning_content from the model's response; ChatMessage only carries
261→    // text + tool_calls, so this path hits a 400. The gateway works around
262→    // this by preserving raw JSON across turns.
263→    let messages = vec![
264→        ChatMessage::user("What's the weather in London? You must use the get_weather tool."),
265→        ChatMessage::assistant_with_tools(None, vec![ToolCall {
266→            id: tc_id.clone(),
267→            name: tc_name.clone(),
268→            arguments: args,
269→            metadata: None,
270→        }]),
271→        ChatMessage::tool(tc_id, r#"{"temperature": 15, "condition": "cloudy"}"#),
272→    ];
273→
274→    match p.complete(&messages, &tools).await {
275→        Ok(response) => {
276→            let text = response.text.expect("should have text response");
277→            assert!(!text.is_empty(), "final response should not be empty");
278→        },
279→        Err(e) => {
280→            let err_str = e.to_string();
281→            if err_str.contains("reasoning_content is missing") {
282→                // Known limitation: ChatMessage doesn't carry reasoning_content.
283→                // In production, the gateway preserves raw JSON across turns.
284→                eprintln!(
285→                    "multi-turn 400 (expected): Moonshot requires reasoning_content \
286→                     from step 1 but ChatMessage doesn't carry it"
287→                );
288→            } else {
289→                panic!("unexpected error in multi-turn: {e}");
290→            }
291→        },
292→    }
293→}
