    }
    eprintln!("\n=== Kimi Code Model Catalog Health ===");
    for m in &alive {
        eprintln!("  OK {m}");
    }
    for (m, e) in &dead {
        eprintln!("  DEAD {m}: {e}");
    }
    eprintln!("=====================================\n");
    assert!(alive.contains(&TEST_MODEL), "{TEST_MODEL} should be live");
}

